CodeInjections.CodeInjection:
    float4 fadeProgress;
    float  fadeScale;
    float  uvSpeedMult;
#if defined( PIPE_EFFECT )
    float4 shapeScaleSpread;
    float4 controlPoint;
#endif

#include "$data/shaders/sharedFunctions_vs.gsl"

float3 getCustomPositionVS( VS_INPUT In, ObjectParameters& object, float mSpeed ) {
    float3 mDeformed = In.position.xyz;
#if defined( PIPE_EFFECT )
    float  mGrad             = convertDefaultTexCoords( In, object, In.texCoords0.xy ).x;
    float  mGradSide         = In.color.g;
    float3 mDeformedPosition = In.position.xyz;
    mDeformedPosition.z     /= 10;
    float mFadeIn            = 0.5 * ( object.fadeProgress.x ) + 0.5;
    mDeformedPosition        = lerp( object.fadeScale * In.normal.xyz, mDeformedPosition, mFadeIn );
    float mSpread            = object.shapeScaleSpread.z;
    mSpread                  = max( 1.0, 1 + mSpread );
    mDeformedPosition.xy     = lerp( mDeformedPosition.xy, mDeformedPosition.xy * mSpread, mGrad );
    float2 mShapeScale       = max( object.shapeScaleSpread.xy, 0.001 );
    mDeformedPosition.xy    *= mShapeScale.xy;
    float mControlPoint      = max( object.controlPoint.x, 0.001 );
    mControlPoint            = mControlPoint - min( sign( mDeformedPosition.z ), 0 ) * ( 10 - mControlPoint );
    mDeformedPosition.z     *= mControlPoint;
    float mFrequency         = mSpeed - mDeformedPosition.z * 3.0;
    float mAmplitude         = 0.1 * mGrad * mGradSide;
    float mOffset            = ( 0.5 * sin( mFrequency ) + 0.5 ) * mAmplitude;
    mDeformedPosition       += mOffset * In.normal.xyz;
    float mAngle             = object.controlPoint.y;
    float3 newPos            = mDeformedPosition;
    mGrad                    = clamp( sin( 1.5 * mGrad ), 0, 1 );
    float mCos               = cos( mAngle );
    float mSin               = sin( mAngle );
    float3 v1                = float3( 0.0, 0.0, 0.0 );
    float3 v2                = float3( 0.0, 0.0, 0.0 );
    v1.y = mCos; v1.z = -mSin;
    v2.y = mSin; v2.z =  mCos;
    newPos.y                 = dot( mDeformedPosition, v1 );
    newPos.z                 = dot( mDeformedPosition, v2 );
    mDeformed                = lerp( mDeformedPosition, newPos, mGrad );
#endif
    return mDeformed.xyz;
}

    Out.defaultTexCoords  = convertDefaultTexCoords( In, object, In.texCoords0.xy );
    Out.defaultTexCoords2 = convertDefaultTexCoords( In, object, In.texCoords1.xy );
#if defined( PIPE_EFFECT )
    float mSpread2            = object.shapeScaleSpread.z;
    mSpread2                  = max( 1.0, 1 + mSpread2 );
    float mGrad2              = Out.defaultTexCoords.x;
    float uvPropScale         = max( object.controlPoint.x, 0.001 );
    Out.defaultTexCoords.x   *= uvPropScale;
    Out.defaultTexCoords2.x  *= uvPropScale;
    uvPropScale               = lerp( 1, mSpread2, mGrad2 );
    Out.defaultTexCoords.y   *= uvPropScale;
    Out.defaultTexCoords2.y  *= uvPropScale;
#endif

    float mSpeed = 36.0 * cTime_s;
    float3 mDeformed = getCustomPositionVS( In, object, mSpeed );
#if defined(SKINNING)
    return skinPoint( mDeformed.xyz, In, instance, object );
#else
    return mDeformed.xyz;
#endif

    float mSpeed = 36.0 * cPrevTime_s;
    float3 mDeformed = getCustomPositionVS( In, object, mSpeed );
#if defined(SKINNING)
    return skinPrevPoint( mDeformed.xyz, In, instance, object );
#else
    return mDeformed.xyz;
#endif

float4 gUV;
float4 gVertexColor;
float  gAlpha;

globals.gVertexColor = In.vs.vertexColor.rgba;
float mUVscale = 1.0;
float mSpeed   = 6.0 * cTime_s * object.uvSpeedMult;
mSpeed         = frac( mSpeed / mUVscale ) * mUVscale;
globals.gUV.xy = mUVscale * In.vs.defaultTexCoords  - float2( mSpeed * mUVscale, 0.0 );
globals.gUV.zw = mUVscale * In.vs.defaultTexCoords2 - float2( mSpeed * mUVscale, 0.0 );
float mText1   = tex2DSample( waterRGB, samplerBilinearWrap, globals.gUV.xy ).r;
float mText2   = tex2DSample( waterRGB, samplerBilinearWrap, globals.gUV.zw ).r;
globals.gAlpha = saturate( mText1 + mText2 );

// Water colour range — clear blue to deep blue
float3 colorA  = float3( 0.10, 0.35, 0.65 );
float3 colorB  = float3( 0.02, 0.10, 0.35 );
diffuseColor   = lerp( colorA, colorB, globals.gAlpha * globals.gAlpha );

float2 mUV      = In.vs.defaultTexCoords / max( object.controlPoint.x, 0.001 );
float mEndAlpha = globals.gVertexColor.a;
mEndAlpha       = alphaGradient( globals.gAlpha, mEndAlpha, 0.05 );
float2 uv1      = float2( object.fadeProgress.x, 0 ) + ( 1 - mUV );
float mFadeIN   = alphaGradient( globals.gAlpha, tex2DSample( fadeMask, samplerBilinearClamp, uv1 ).x, 0.1 );
float2 uv2      = float2( object.fadeProgress.y, 0 ) + mUV;
float mFadeOUT  = alphaGradient( globals.gAlpha, tex2DSample( fadeMask, samplerBilinearClamp, uv2 ).x, 0.1 );
alpha           = saturate( mEndAlpha * mFadeIN * mFadeOUT );

{
    float unclampedNdotL = dot( normal, lightDir );
    diffuseIrradiance    = atten * saturate( unclampedNdotL > 0.0 ? unclampedNdotL : -unclampedNdotL * 0.25 );
}
